Javascript.validate:
// defect UCT 600 re currency validation 
var value = Services.getValue(InstalmentAmount.dataBinding);
var errCode = null;
if(!CaseManUtils.isBlank(value)) {
	if(!CaseManValidationHelper.validateFloatNumber(value)){
		errCode = ErrorCode.getErrorCode("CaseMan_Reports_Enter_Number");
	}
	else{
		// defect UCT 600 re currency validation - NB multi returns in method here
		// originaly so kept them.
		errCode =  CaseManValidationHelper.validatePattern(value, CaseManValidationHelper.CURRENCY_PATTERN, "CaseMan_invalidAmountFormat_Msg");
		if(errCode == null){
			if(value <= 0){
				errCode = ErrorCode.getErrorCode("CaseMan_Reports_Enter_Number");
			}
		}
	}				
	//return CaseManValidationHelper.validatePattern(value, CaseManValidationHelper.NUMERIC_PATTERN, "CaseMan_Reports_Enter_Number");
}			
return errCode;
